CREATE TABLE `wp_amelia_customer_bookings` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `appointmentId` int(11) DEFAULT NULL,
  `customerId` int(11) NOT NULL,
  `status` enum('approved','pending','canceled','rejected','no-show','waiting') DEFAULT NULL,
  `price` double NOT NULL,
  `tax` varchar(255) DEFAULT NULL,
  `persons` int(11) NOT NULL,
  `couponId` int(11) DEFAULT NULL,
  `token` varchar(10) DEFAULT NULL,
  `customFields` text DEFAULT NULL,
  `info` text DEFAULT NULL,
  `utcOffset` int(3) DEFAULT NULL,
  `aggregatedPrice` tinyint(1) DEFAULT 1,
  `packageCustomerServiceId` int(11) DEFAULT NULL,
  `duration` int(11) DEFAULT NULL,
  `created` datetime DEFAULT NULL,
  `actionsCompleted` tinyint(1) DEFAULT NULL,
  `qrCodes` text DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=140 DEFAULT CHARSET=utf8mb3 COLLATE=utf8mb3_general_ci;
